%[text] # 例3.1（矩形フィルタ）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example03_09"; % mfilename

imgname = "msipimg08";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');
%%
%[text] ## フィルタ処理前の画像表示
figure(1) %[output:64078bdf]
imshow(X)  %[output:64078bdf]
title('原画像')  %[output:64078bdf]

%%
%[text] ## 観測画像
V = imnoise(X,'salt & pepper');
figure(2) %[output:3785ec24]
imshow(V) %[output:3785ec24]
title('観測画像')  %[output:3785ec24]

%%
%[text] ## 観測画像
Y = medfilt2(V);
figure(3) %[output:2a48df68]
imshow(Y) %[output:2a48df68]
title('処理画像')  %[output:2a48df68]


%%
%[text] ## 結果出力
imwrite(X,fullfile(resfolder,"fig03-06a.png"))
imwrite(V,fullfile(resfolder,"fig03-06b.png"))
imwrite(Y,fullfile(resfolder,"fig03-06c.png"))

